108→/*
109→ * Requires:
110→ *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
111→ *   parameter "uri" must point to a properly NUL-terminated string.
112→ *
113→ * Effects:
114→ *   Returns a string containing a properly formatted log entry.  This log
115→ *   entry is based upon the socket address of the requesting client
116→ *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
117→ *   the response from the server ("size").
118→ */
119→static char *
120→create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
121→{
122→	struct tm result;
123→
124→	/*
125→	 * Create a large enough array of characters to store a log entry.
126→	 * Although the length of the URI can exceed MAXLINE, the combined
127→	 * lengths of the other fields and separators cannot.
128→	 */
129→	const size_t log_maxlen = MAXLINE + strlen(uri);
130→	char *const log_str = Malloc(log_maxlen + 1);
131→
132→	/* Get a formatted time string. */
133→	time_t now = time(NULL);
134→	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
135→	    localtime_r(&now, &result));
136→
137→	/*
138→	 * Convert the IP address in network byte order to dotted decimal
139→	 * form.
140→	 */
141→	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
142→	    INET_ADDRSTRLEN);
143→	log_strlen += strlen(&log_str[log_strlen]);
144→
145→	/*
146→	 * Assert that the time and IP address fields occupy less than half of
147→	 * the space that is reserved for the non-URI fields.
148→	 */
149→	assert(log_strlen < MAXLINE / 2);
150→
151→	/*
152→	 * Add the URI and response size onto the end of the log entry.
153→	 */
154→	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
155→	    size);
156→
157→	return (log_str);
158→}
