   115→/* Rio (Robust I/O) package */
   116→ssize_t rio_readn(int fd, void *usrbuf, size_t n) {
   117→    size_t nleft = n;
   118→    ssize_t nread;
   119→    char *bufp = usrbuf;
   120→
   121→    while (nleft > 0) {
   122→        if ((nread = read(fd, bufp, nleft)) < 0) {
   123→            if (errno == EINTR)
   124→                nread = 0;
   125→            else
   126→                return -1;
   127→        } else if (nread == 0)
   128→            break;
   129→        nleft -= nread;
   130→        bufp += nread;
   131→    }
   132→    return (n - nleft);
   133→}
   134→
   135→ssize_t rio_writen(int fd, void *usrbuf, size_t n) {
   136→    size_t nleft = n;
   137→    ssize_t nwritten;
   138→    char *bufp = usrbuf;
   139→
   140→    while (nleft > 0) {
   141→        if ((nwritten = write(fd, bufp, nleft)) <= 0) {
   142→            if (errno == EINTR)
   143→                nwritten = 0;
   144→            else
   145→                return -1;
   146→        }
   147→        nleft -= nwritten;
   148→        bufp += nwritten;
   149→    }
   150→    return n;
   151→}
