   159→static ssize_t rio_read(rio_t *rp, char *usrbuf, size_t n) {
   160→    int cnt;
   161→
   162→    while (rp->rio_cnt <= 0) {
   163→        rp->rio_cnt = read(rp->rio_fd, rp->rio_buf, sizeof(rp->rio_buf));
   164→        if (rp->rio_cnt < 0) {
   165→            if (errno != EINTR)
   166→                return -1;
   167→        } else if (rp->rio_cnt == 0)
   168→            return 0;
   169→        else
   170→            rp->rio_bufptr = rp->rio_buf;
   171→    }
   172→
   173→    cnt = n;
   174→    if ((size_t)rp->rio_cnt < n)
   175→        cnt = rp->rio_cnt;
   176→    memcpy(usrbuf, rp->rio_bufptr, cnt);
   177→    rp->rio_bufptr += cnt;
   178→    rp->rio_cnt -= cnt;
   179→    return cnt;
   180→}
