/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy using prethreading
 * with a pool of worker threads and a shared connection buffer.
 * Synchronization uses pthread mutex and condition variables (no semaphores).
 */

#include <assert.h>

#include "csapp.h"

/* Configuration constants. */
#define SBUF_SIZE	16	/* Shared buffer capacity */
#define NTHREADS	4	/* Number of worker threads */

/*
 * Shared buffer for connection file descriptors.
 * Uses pthread mutex and condition variables (no semaphores).
 */
typedef struct {
	int		*buf;		/* Buffer array */
	int		 n;		/* Maximum number of slots */
	int		 front;		/* Index of front item */
	int		 rear;		/* Index past rear item */
	int		 count;		/* Number of items in buffer */
	pthread_mutex_t	 mutex;
	pthread_cond_t	 not_empty;
	pthread_cond_t	 not_full;
} sbuf_t;

/* Function prototypes. */
static void	 client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char	*create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static void	 handle_request(int connfd);
static int	 open_clientfd_ts(const char *hostname, const char *port);
static int	 parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);
static char	*read_requestline(rio_t *rp);
static void	 sbuf_init(sbuf_t *sp, int n);
static void	 sbuf_insert(sbuf_t *sp, int item);
static int	 sbuf_remove(sbuf_t *sp);
static void	*thread_routine(void *vargp);

/* Global state. */
static FILE		*log_file;
static pthread_mutex_t	 log_mutex = PTHREAD_MUTEX_INITIALIZER;
static sbuf_t		 sbuf;

/*
 * Requires:
 *   The command line must provide exactly one argument: the port number.
 *
 * Effects:
 *   Starts the proxy server. Opens the log file, initializes the shared
 *   buffer, creates worker threads, then enters the main accept loop.
 */
int
main(int argc, char **argv)
{
	int listenfd, connfd;
	struct sockaddr_in clientaddr;
	socklen_t clientlen;
	pthread_t tid;
	int i;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/* Ignore SIGPIPE to prevent crashes on broken connections. */
	Signal(SIGPIPE, SIG_IGN);

	/* Open the log file once during initialization. */
	log_file = Fopen("proxy.log", "a");

	/* Initialize the shared buffer. */
	sbuf_init(&sbuf, SBUF_SIZE);

	/* Create the pool of worker threads. */
	for (i = 0; i < NTHREADS; i++)
		Pthread_create(&tid, NULL, thread_routine, NULL);

	/* Open the listening socket. */
	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "open_listenfd failed on port %s\n", argv[1]);
		exit(1);
	}

	/* Main accept loop. */
	while (1) {
		clientlen = sizeof(clientaddr);
		connfd = accept(listenfd, (SA *)&clientaddr, &clientlen);
		if (connfd < 0)
			continue;
		sbuf_insert(&sbuf, connfd);
	}

	/* Not reached. */
	return (0);
}

/*
 * Requires:
 *   sp points to a valid sbuf_t structure. n > 0.
 *
 * Effects:
 *   Initializes the shared buffer with capacity n slots.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Calloc(n, sizeof(int));
	sp->n = n;
	sp->front = 0;
	sp->rear = 0;
	sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->not_empty, NULL);
	pthread_cond_init(&sp->not_full, NULL);
}

/*
 * Requires:
 *   sp points to an initialized sbuf_t.
 *
 * Effects:
 *   Inserts item into the buffer, blocking until a slot is available.
 */
static void
sbuf_insert(sbuf_t *sp, int item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->count == sp->n)
		pthread_cond_wait(&sp->not_full, &sp->mutex);
	sp->buf[sp->rear] = item;
	sp->rear = (sp->rear + 1) % sp->n;
	sp->count++;
	pthread_cond_signal(&sp->not_empty);
	pthread_mutex_unlock(&sp->mutex);
}

/*
 * Requires:
 *   sp points to an initialized sbuf_t.
 *
 * Effects:
 *   Removes and returns the front item from the buffer, blocking until
 *   an item is available.
 */
static int
sbuf_remove(sbuf_t *sp)
{
	int item;

	pthread_mutex_lock(&sp->mutex);
	while (sp->count == 0)
		pthread_cond_wait(&sp->not_empty, &sp->mutex);
	item = sp->buf[sp->front];
	sp->front = (sp->front + 1) % sp->n;
	sp->count--;
	pthread_cond_signal(&sp->not_full);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

/*
 * Requires:
 *   hostname and port point to valid NUL-terminated strings.
 *
 * Effects:
 *   Opens a client connection to hostname:port. Returns the file descriptor
 *   on success, or -1 on failure. Thread-safe; properly handles DNS failure.
 */
static int
open_clientfd_ts(const char *hostname, const char *port)
{
	int clientfd, rc;
	struct addrinfo hints, *listp, *p;

	memset(&hints, 0, sizeof(struct addrinfo));
	hints.ai_socktype = SOCK_STREAM;
	hints.ai_flags = AI_NUMERICSERV | AI_ADDRCONFIG;

	rc = getaddrinfo(hostname, port, &hints, &listp);
	if (rc != 0)
		return (-1);

	for (p = listp; p != NULL; p = p->ai_next) {
		clientfd = socket(p->ai_family, p->ai_socktype,
		    p->ai_protocol);
		if (clientfd < 0)
			continue;
		if (connect(clientfd, p->ai_addr, p->ai_addrlen) != -1)
			break;
		close(clientfd);
	}

	freeaddrinfo(listp);
	if (p == NULL)
		return (-1);
	return (clientfd);
}

/*
 * Requires:
 *   rp points to an initialized rio_t.
 *
 * Effects:
 *   Reads a complete line (ending in '\n') from rp, dynamically expanding
 *   the buffer to handle lines longer than MAXLINE. Returns a dynamically
 *   allocated NUL-terminated string, or NULL on error/EOF. Caller must free.
 */
static char *
read_requestline(rio_t *rp)
{
	size_t bufsize, total;
	ssize_t n;
	char *buf, *newbuf;

	bufsize = MAXLINE;
	total = 0;
	buf = malloc(bufsize);
	if (buf == NULL)
		return (NULL);

	while (1) {
		n = rio_readlineb(rp, buf + total, bufsize - total);
		if (n <= 0) {
			free(buf);
			return (NULL);
		}
		total += n;
		/* Check if we got a complete line (ends with '\n'). */
		if (buf[total - 1] == '\n')
			break;
		/* Line isn't complete; expand the buffer. */
		bufsize *= 2;
		newbuf = realloc(buf, bufsize);
		if (newbuf == NULL) {
			free(buf);
			return (NULL);
		}
		buf = newbuf;
	}
	return (buf);
}

/*
 * Requires:
 *   connfd is a valid, open socket connected to a client.
 *
 * Effects:
 *   Handles a single HTTP GET request. Reads the request from the client,
 *   connects to the end server, forwards the request (rewriting the first
 *   line and filtering persistent-connection headers), forwards the
 *   response back, and logs the completed transaction.
 */
static void
handle_request(int connfd)
{
	rio_t client_rio;
	struct sockaddr_in clientaddr;
	socklen_t clientlen;
	char *reqline, *uri, *hostname, *port, *pathname;
	char *saveptr, *tok_method, *tok_uri;
	char method[16], hdrbuf[MAXBUF], line[MAXLINE], reqbuf[MAXLINE];
	char buf[MAXBUF];
	int hdrlen, has_host, serverfd, total_size, reqlen, llen;
	ssize_t n;

	uri = NULL;
	hostname = NULL;
	port = NULL;
	pathname = NULL;
	serverfd = -1;

	/* Get the client's address for logging. */
	clientlen = sizeof(clientaddr);
	if (getpeername(connfd, (SA *)&clientaddr, &clientlen) < 0)
		return;

	/* Initialize RIO for reading from the client. */
	rio_readinitb(&client_rio, connfd);

	/* Read the request line (handles URIs longer than MAXLINE). */
	reqline = read_requestline(&client_rio);
	if (reqline == NULL)
		return;

	/* Parse method and URI from the request line. */
	tok_method = strtok_r(reqline, " \t", &saveptr);
	tok_uri = strtok_r(NULL, " \t\r\n", &saveptr);
	if (tok_method == NULL || tok_uri == NULL) {
		client_error(connfd, "", 400, "Bad Request",
		    "Malformed request line");
		free(reqline);
		return;
	}

	/* Save method and URI before freeing the request line buffer. */
	strncpy(method, tok_method, sizeof(method) - 1);
	method[sizeof(method) - 1] = '\0';
	uri = strdup(tok_uri);
	free(reqline);
	if (uri == NULL)
		return;

	/* Only support the GET method. */
	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "Proxy does not support this method");
		free(uri);
		return;
	}

	/* Parse the URI into hostname, port, pathname. */
	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(connfd, uri, 400, "Bad Request",
		    "Could not parse the URI");
		free(uri);
		return;
	}

	/* Read and filter request headers from the client. */
	hdrlen = 0;
	has_host = 0;
	while ((n = rio_readlineb(&client_rio, line, sizeof(line))) > 0) {
		/* An empty line signals the end of the headers. */
		if (strcmp(line, "\r\n") == 0 || strcmp(line, "\n") == 0)
			break;
		/* Strip persistent-connection headers. */
		if (strncasecmp(line, "Connection:", 11) == 0 ||
		    strncasecmp(line, "Keep-Alive:", 11) == 0 ||
		    strncasecmp(line, "Proxy-Connection:", 17) == 0)
			continue;
		if (strncasecmp(line, "Host:", 5) == 0)
			has_host = 1;
		/* Append header to buffer if there is room. */
		llen = (int)strlen(line);
		if (hdrlen + llen < (int)sizeof(hdrbuf)) {
			memcpy(hdrbuf + hdrlen, line, llen);
			hdrlen += llen;
		}
	}

	/* Connect to the end server. */
	serverfd = open_clientfd_ts(hostname, port);
	if (serverfd < 0) {
		client_error(connfd, hostname, 502, "Bad Gateway",
		    "Could not connect to the end server");
		goto cleanup;
	}

	/* Send the modified request line to the server. */
	reqlen = snprintf(reqbuf, sizeof(reqbuf),
	    "GET %s HTTP/1.0\r\n", pathname);
	if (rio_writen(serverfd, reqbuf, reqlen) < 0)
		goto cleanup;

	/* Add a Host header if the client did not provide one. */
	if (!has_host) {
		reqlen = snprintf(reqbuf, sizeof(reqbuf),
		    "Host: %s\r\n", hostname);
		if (rio_writen(serverfd, reqbuf, reqlen) < 0)
			goto cleanup;
	}

	/* Add a Connection: close header. */
	if (rio_writen(serverfd, "Connection: close\r\n", 19) < 0)
		goto cleanup;

	/* Forward the remaining request headers. */
	if (hdrlen > 0 && rio_writen(serverfd, hdrbuf, hdrlen) < 0)
		goto cleanup;

	/* Send the empty line to end the request headers. */
	if (rio_writen(serverfd, "\r\n", 2) < 0)
		goto cleanup;

	/* Forward the response from the server to the client. */
	total_size = 0;
	while ((n = rio_readn(serverfd, buf, sizeof(buf))) > 0) {
		total_size += n;
		if (rio_writen(connfd, buf, n) < 0)
			break;
	}

	/* Log the completed transaction if any data was received. */
	if (total_size > 0) {
		char *log_entry = create_log_entry(&clientaddr, uri,
		    total_size);
		pthread_mutex_lock(&log_mutex);
		fprintf(log_file, "%s\n", log_entry);
		fflush(log_file);
		pthread_mutex_unlock(&log_mutex);
		free(log_entry);
	}

cleanup:
	if (serverfd >= 0)
		close(serverfd);
	free(hostname);
	free(port);
	free(pathname);
	free(uri);
}

/*
 * Requires:
 *   vargp is unused.
 *
 * Effects:
 *   Worker thread routine. Detaches itself, then continuously removes
 *   connection descriptors from the shared buffer, handles the request,
 *   and closes the connection.
 */
static void *
thread_routine(void *vargp)
{
	int connfd;

	(void)vargp;
	Pthread_detach(Pthread_self());
	while (1) {
		connfd = sbuf_remove(&sbuf);
		handle_request(connfd);
		close(connfd);
	}
	return (NULL);
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}
